What will be the output of the following C code snippet?
#include <stdio.h>
int main() {
    int a[] = {10, 20, 30, 40};
    int *p = a;
    printf("%d ", *++p);
    printf("%d", ++*p);
    return 0;
}

Consider the following macro definition. What will be the value of `y`?
#define CUBE(x) (x * x * x)
int main() {
    int a = 2;
    int y = CUBE(a + 1);
    printf("%d", y);
    return 0;
}

What is the expected output when the `sizeof` operator is applied to the following character array in a standard 32-bit/64-bit C compiler?
char str[15] = "JECA2026";
printf("%zu %zu", sizeof(str), strlen(str));

Which of the following describes the correct memory padding/alignment behavior for the following struct on a 32-bit architecture?
struct Test {
    char a;
    int b;
    char c;
};

How many total processes will be created by the execution of the following C code block?
int main() {
    fork();
    fork();
    fork();
    return 0;
}

What does the following C expression efficiently accomplish for integer variables `a` and `b`?
 a ^= b; 
 b ^= a; 
 a ^= b;

Predict the output of the following C snippet:
#include <stdio.h>
int main() {
    int a = 10, b = 20, c = 30;
    int result = a > b ? a : b > c ? b : c;
    printf("%d", result);
    return 0;
}

What is the output of the following C code?
#include <stdio.h>
int main() {
    int a = 1;
    switch(a) {
        case 1:
            printf("One ");
        case 2:
            printf("Two ");
            break;
        default:
            printf("None");
    }
    return 0;
}
